const form=document.getElementById("contact-form");form.addEventListener("submit",async e=>{e.preventDefault();const a={name:form.name.value,email:form.email.value,message:form.message.value};try{await sendEmail(a),alert("Email sent!"),form.reset()}catch(e){alert("Something went wrong")}});const sendEmail=async e=>{const a=await fetch("https://api.emailjs.com/api/v1.0/email/send",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({service_id:"service_1lyynb6",template_id:"template_6tr4xl8",user_id:"4xwela_zSErdUA7yK",template_params:{from_name:e.name,from_email:e.email,message:e.message}})});if(!a.ok)throw new Error("Failed to send email");return a.text()};